var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"마스터!","JPN":"マスター！","ENG":"Master!","TWN":"主人！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"어째서 배신자가 활개치는 이런 누추한 곳에......! 어서 몸을 피하셔야 해요!","JPN":"なぜ裏切り者が横行するこんなむさくるしい場所に……！　早く安全な場所に避難してください！","ENG":"The traitor does not deserve to be graced with your presence! Please, you must get to safety!","TWN":"這裡叛徒橫行，您怎麼可以來到如此髒亂的地方……！請您回避！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"바람도 잔잔한데 그만 바스락거리렴. 정신 사납구나.","JPN":"こんなにも風が穏やかなのに、あなたはどうしてそんななびくのかしら。気が散ってしょうがないわね。","ENG":"Quit your noisy rustling. You're disturbing the peaceful air.","TWN":"清風徐徐，就不要在那裡沙沙作響了，太吵了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"네......?","JPN":"え……？","ENG":"Master?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"자, 베로니카. 어서 저 잡초를 솎아내렴.","JPN":"さあ、ベロニカ。早くあの雑草を間引きなさい。","ENG":"Now, Veronica. Go on and pluck that weed.","TWN":"貝洛妮卡，快除掉那個雜草吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"기회는 아직 유효하단다.","JPN":"まだチャンスは有効よ。","ENG":"The offer I gave you still stands.","TWN":"你現在還有機會。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"기, 기다려 주세요!","JPN":"お、お待ちください！","ENG":"P-please wait!","TWN":"等、等等！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"분명, 배신자를 솎아내는 데에는 실패했지만 마스터에 대한 충성심은 변하지 않았습니다!","JPN":"確かに、裏切り者の間引きには失敗しましたが、マスターへの忠誠心に代わりはございません！","ENG":"Although I've clearly failed to pluck out the traitor, my loyalty for you has not changed!","TWN":"雖然我沒能除掉叛徒，但我對主人您的忠心卻從來沒有變過！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그런데...... 그런데 어째서 저를 잡초 취급 하시는 건가요!","JPN":"それなのに……どうして私を雑草と呼ぶのでしょうか？","ENG":"But why... Why are you treating me like a weed?","TWN":"可是……可是您為什麼只當我是雜草呢！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"정말 눈치가 없구나, 너는.","JPN":"本当にあなたって子は空気が読めないのね。","ENG":"You really are clueless, aren't you?","TWN":"你真是沒眼力。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그야 네가 마음에 안 들어서 그렇지.","JPN":"あなたが気に入らないからに決まってるじゃない。","ENG":"That's because I simply don't like you, of course.","TWN":"當然是因為我不喜歡你啊。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"마음에...... 안 들어서?","JPN":"気に……入らない？","ENG":"Because you don't... like me?","TWN":"不……喜歡？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래. 너처럼 비실거리고 분위기도 어두침침한 아이를 어디에 데려다 쓰겠니.","JPN":"そうよ。あなたのように弱くて暗い子に使い道があると思ってるの？","ENG":"That's right. What use would I have for a frail, gloomy urchin like you?","TWN":"像你這麼弱不禁風又陰森森的人能幹什麼。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"적당히 써먹다 폐기할 생각이었는데, 베로니카가 널 꽤 아끼는 것 같아서 내버려 둔 거란다.","JPN":"適当に使って廃棄するつもりだったのに、ベロニカはあなたのことが相当気に入ったようだからしばらく放っておいただけよ。","ENG":"I was planning to discard of you once you'd served me however little you could, but then I decided to let you be, since Veronica seemed to be quite fond of you.","TWN":"本想隨便用用就扔了的，沒想到貝洛妮卡還挺喜歡你，所以我才留你活命。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"베로니카도 참 상냥하지. 금방 질릴 줄 알았는데 아직도 미련을 못 버린 모양이야.","JPN":"ベロニカったらなんて優しいのかしら。そのうち飽きると思ったのに、まだ未練があるとはね。","ENG":"Oh, sweet Veronica. I thought you would get tired of her quickly, but you still seem to be somewhat attached.","TWN":"貝洛妮卡也是善良，本以為沒多久就會厭倦，沒想到現在也沒放棄。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"마, 마스터...... 제가 잘못 들은 거죠? 그렇죠?","JPN":"マ、マスター……今のは私の聞き間違えですよね？　そうですよね？","ENG":"M-Master... I must have misheard you, right?","TWN":"主、主人……是我聽錯了吧？對不對？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"네가 잘못 들었는지 아닌지는 내 알 바 아니잖니.","JPN":"あなたが聞き間違えたかどうかなんて知ったことではないわ。","ENG":"I really couldn't care less if you heard me correctly or not.","TWN":"你聽沒聽錯跟我沒什麼關係。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};